const Cache = require('./src/query-cache');
Cache.resetStats();

// Simulate first query (cache miss)
console.log('=== Query 1: cache miss ===');
const result1 = { results: [{ id: 'a' }], totalResults: 1 };
Cache.set('buildCodeText|3', result1);
console.log('Stored:', Cache.getStats());

// Simulate second query (cache hit) — same key, no Qdrant call needed
console.log('\n=== Query 2: cache hit ===');
const cached = Cache.get('buildCodeText|3');
if (cached !== undefined) {
  console.log('Cache HIT — served from memory:', JSON.stringify(cached));
} else {
  console.log('ERROR: expected cache hit but got miss');
  process.exit(1);
}

// Verify stats show 1 hit, 0 misses
const stats = Cache.getStats();
console.log('\n=== Stats ===');
console.log(JSON.stringify(stats));
if (stats.hits !== 1 || stats.misses !== 0) {
  console.error('FAIL: expected hits=1,misses=0');
  process.exit(1);
}

// Test has() doesn't update TTL — entry should still be valid after delay
console.log('\n=== has() does not refresh TTL ===');
Cache.set('ttl-test', 'value');
const exists = Cache.has('ttl-test');
console.log('has() returned:', exists, '(should be true)');

// Test clear
Cache.clear();
console.log('After clear — size:', Cache.store.size);

console.log('\n✅ All cache tests passed');
